class PaymentGatewayService {
  final PaymentBackendClient backend;
  final PaymentLogger _log;

  PaymentGatewayService(this.backend, {PaymentLogger? logger}) : _log = logger ?? const PaymentLogger();

  Future<PaymentGatewayIntent> createWalletIntent({
    required PaymentMethodType method,
    required String currency,
    required int amountMinor,
    required String countryCode,
    required String description,
    Map<String, dynamic>? metadata,
  }) async {
    final res = await backend.postJson('/payments/wallet/intent', {
      'method': describeEnum(method),
      'currency': currency,
      'amountMinor': amountMinor,
      'countryCode': countryCode,
      'description': description,
      'metadata': metadata ?? <String, dynamic>{},
      'environment': describeEnum(backend.config.environment),
    });
    final orderId = (res['orderId'] ?? '').toString();
    final clientSecret = (res['clientSecret'] ?? '').toString();
    final provider = (res['provider'] ?? '').toString();
    if (orderId.isEmpty || clientSecret.isEmpty) {
      throw PaymentException('invalid_intent', 'Invalid intent response', details: res);
    }
    _log.info('Created wallet intent', data: {'orderId': orderId, 'provider': provider});
    return PaymentGatewayIntent(orderId: orderId, clientSecret: clientSecret, provider: provider, raw: res);
  }

  Future<Map<String, dynamic>> confirmWalletPayment({
    required String orderId,
    required PaymentMethodType method,
    required String walletToken,
    Map<String, dynamic>? deviceData,
  }) async {
    return backend.postJson('/payments/wallet/confirm', {
      'orderId': orderId,
      'method': describeEnum(method),
      'walletToken': walletToken,
      'deviceData': deviceData ?? <String, dynamic>{},
      'environment': describeEnum(backend.config.environment),
    });
  }

  Future<Map<String, dynamic>> verifyIapReceipt({
    required String platform,
    required String productId,
    required String purchaseId,
    required String receiptOrToken,
    required bool isSubscription,
    Map<String, dynamic>? extra,
  }) async {
    return backend.postJson('/payments/iap/verify', {
      'platform': platform,
      'productId': productId,
      'purchaseId': purchaseId,
      'receiptOrToken': receiptOrToken,
      'isSubscription': isSubscription,
      'extra': extra ?? <String, dynamic>{},
      'environment': describeEnum(backend.config.environment),
    });
  }
}

