class WalletIntegration {
  static const MethodChannel _channel = MethodChannel('com.yourcompany.payments/wallet');

  final PaymentConfig config;
  final PaymentLogger _log;

  WalletIntegration(this.config, {PaymentLogger? logger}) : _log = logger ?? const PaymentLogger();

  Future<bool> isSupported(PaymentMethodType method) async {
    try {
      final res = await _channel.invokeMethod<bool>('isSupported', {
        'method': describeEnum(method),
        'environment': describeEnum(config.environment),
        'applePayMerchantId': config.applePayMerchantId,
        'googlePayMerchantId': config.googlePayMerchantId,
      });
      return res ?? false;
    } on PlatformException catch (e) {
      _log.warn('Wallet isSupported failed', data: {'code': e.code, 'message': e.message});
      return false;
    }
  }

  Future<String> presentWalletSheet({
    required PaymentMethodType method,
    required String merchantName,
    required String countryCode,
    required String currencyCode,
    required int amountMinor,
    required String label,
    required String clientSecret,
    required String orderId,
  }) async {
    if (method != PaymentMethodType.applePay && method != PaymentMethodType.googlePay) {
      throw PaymentException('invalid_method', 'Wallet sheet supports Apple Pay / Google Pay only');
    }
    try {
      final token = await _channel.invokeMethod<String>('presentWalletSheet', {
        'method': describeEnum(method),
        'merchantName': merchantName,
        'countryCode': countryCode,
        'currencyCode': currencyCode,
        'amountMinor': amountMinor,
        'label': label,
        'clientSecret': clientSecret,
        'orderId': orderId,
        'environment': describeEnum(config.environment),
        'applePayMerchantId': config.applePayMerchantId,
        'googlePayMerchantId': config.googlePayMerchantId,
      });
      if (token == null || token.isEmpty) {
        throw PaymentException('wallet_no_token', 'No wallet token returned');
      }
      return token;
    } on PlatformException catch (e) {
      if (e.code == 'canceled') {
        throw PaymentException('canceled', 'User canceled');
      }
      throw PaymentException('wallet_error', e.message ?? 'Wallet error', details: {'code': e.code, 'details': e.details});
    }
  }
}

