class IapService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentGatewayService gateway;
  final PaymentLogger _log;

  StreamSubscription<List<PurchaseDetails>>? _purchaseSub;
  final StreamController<PaymentResult> _results = StreamController.broadcast();

  Stream<PaymentResult> get results => _results.stream;

  IapService(this.gateway, {PaymentLogger? logger}) : _log = logger ?? const PaymentLogger();

  Future<bool> isAvailable() => _iap.isAvailable();

  Future<List<IapProduct>> queryProducts(Set<String> productIds, {Set<String> subscriptionIds = const {}}) async {
    final resp = await _iap.queryProductDetails(productIds);
    if (resp.error != null) {
      throw PaymentException('iap_query_error', resp.error!.message, details: resp.error);
    }
    final products = resp.productDetails.map((p) {
      final isSub = subscriptionIds.contains(p.id);
      return IapProduct(
        id: p.id,
        title: p.title,
        description: p.description,
        price: p.price,
        currencyCode: p.currencyCode,
        isSubscription: isSub,
        raw: p,
      );
    }).toList();
    return products;
  }

  Future<void> startListening() async {
    await _purchaseSub?.cancel();
    _purchaseSub = _iap.purchaseStream.listen(
      (purchases) async {
        for (final p in purchases) {
          await _handlePurchase(p);
        }
      },
      onError: (e) {
        _log.error('purchaseStream error', data: {'error': e.toString()});
      },
    );
  }

  Future<void> stopListening() async {
    await _purchaseSub?.cancel();
    _purchaseSub = null;
  }

  Future<void> buy(IapProduct product, {String? applicationUserName}) async {
    final purchaseParam = PurchaseParam(productDetails: product.raw, applicationUserName: applicationUserName);
    if (product.isSubscription) {
      await _iap.buyNonConsumable(purchaseParam: purchaseParam);
    } else {
      await _iap.buyConsumable(purchaseParam: purchaseParam, autoConsume: Platform.isAndroid);
    }
    _results.add(PaymentResult(status: PaymentStatus.initiated, method: PaymentMethodType.inAppPurchase));
  }

  Future<void> restore() => _iap.restorePurchases();

  Future<void> _handlePurchase(PurchaseDetails p) async {
    if (p.status == PurchaseStatus.pending) {
      _results.add(PaymentResult(
        status: PaymentStatus.pending,
        method: PaymentMethodType.inAppPurchase,
        transactionId: p.purchaseID,
        orderId: p.productID,
        raw: {'status': 'pending'},
      ));
      return;
    }

    if (p.status == PurchaseStatus.canceled) {
      _results.add(PaymentResult(
        status: PaymentStatus.canceled,
        method: PaymentMethodType.inAppPurchase,
        transactionId: p.purchaseID,
        orderId: p.productID,
        message: 'Canceled',
      ));
      if (p.pendingCompletePurchase) {
        await _iap.completePurchase(p);
      }
      return;
    }

    if (p.status == PurchaseStatus.error) {
      _results.add(PaymentResult(
        status: PaymentStatus.failed,
        method: PaymentMethodType.inAppPurchase,
        transactionId: p.purchaseID,
        orderId: p.productID,
        message: p.error?.message ?? 'IAP error',
        raw: {'error': p.error?.details},
      ));
      if (p.pendingCompletePurchase) {
        await _iap.completePurchase(p);
      }
      return;
    }

    if (p.status == PurchaseStatus.purchased || p.status == PurchaseStatus.restored) {
      try {
        final platform = Platform.isIOS ? 'ios' : 'android';
        final receiptOrToken = p.verificationData.serverVerificationData;
        final isSubscription = _guessSubscription(p);
        final verify = await gateway.verifyIapReceipt(
          platform: platform,
          productId: p.productID,
          purchaseId: p.purchaseID ?? '',
          receiptOrToken: receiptOrToken,
          isSubscription: isSubscription,
          extra: {
            'source': p.status == PurchaseStatus.restored ? 'restored' : 'purchased',
            'localVerificationData': p.verificationData.localVerificationData,
            'verificationSource': describeEnum(p.verificationData.source),
          },
        );

        final ok = (verify['ok'] == true) || (verify['status'] == 'succeeded');
        if (!ok) {
          throw PaymentException('iap_verify_failed', 'Receipt verification failed', details: verify);
        }

        _results.add(PaymentResult(
          status: PaymentStatus.succeeded,
          method: PaymentMethodType.inAppPurchase,
          transactionId: p.purchaseID,
          orderId: verify['orderId']?.toString() ?? p.productID,
          receiptOrToken: receiptOrToken,
          gatewayReference: verify['gatewayReference']?.toString(),
          raw: verify,
        ));
      } catch (e) {
        _results.add(PaymentResult(
          status: PaymentStatus.failed,
          method: PaymentMethodType.inAppPurchase,
          transactionId: p.purchaseID,
          orderId: p.productID,
          message: e.toString(),
        ));
      } finally {
        if (p.pendingCompletePurchase) {
          await _iap.completePurchase(p);
        }
      }
    }
  }

  bool _guessSubscription(PurchaseDetails p) {
    final id = p.productID.toLowerCase();
    return id.contains('sub') || id.contains('subscription') || id.contains('monthly') || id.contains('yearly');
  }

  Future<void> dispose() async {
    await stopListening();
    await _results.close();
  }
}

class PaymentModule {
  final PaymentConfig config;
  final PaymentLogger log;

  late final PaymentBackendClient backend;
  late final PaymentGatewayService gateway;
  late final WalletIntegration wallet;
  late final IapService iap;

  PaymentModule._(this.config, this.log) {
    backend = PaymentBackendClient(config, logger: log);
    gateway = PaymentGatewayService(backend, logger: log);
    wallet = WalletIntegration(config, logger: log);
    iap = IapService(gateway, logger: log);
  }

  static Future<PaymentModule> initialize(PaymentConfig config, {PaymentLogger? logger}) async {
    final log = logger ?? const PaymentLogger();
    final module = PaymentModule._(config, log);
    await module.iap.startListening();
    return module;
  }

  Future<void> dispose() async {
    await iap.dispose();
    backend.close();
  }

  Future<WalletPaymentResponse> payWithWallet({
    required WalletPaymentRequest request,
    required String merchantName,
    required String label,
    Map<String, dynamic>? deviceData,
  }) async {
    if (request.method != PaymentMethodType.applePay && request.method != PaymentMethodType.googlePay) {
      throw PaymentException('invalid_method', 'Use applePay or googlePay for wallet payments');
    }

    final supported = await wallet.isSupported(request.method);
    if (!supported) {
      throw PaymentException('not_supported', 'Wallet not supported on this device');
    }

    final intent = await gateway.createWalletIntent(
      method: request.method,
      currency: request.currency,
      amountMinor: request.amountMinor,
      countryCode: request.countryCode,
      description: request.description,
      metadata: request.metadata,
    );

    final token = await wallet.presentWalletSheet(
      method: request.method,
      merchantName: merchantName,
      countryCode: request.countryCode,
      currencyCode: request.currency,
      amountMinor: request.amountMinor,
      label: label,
      clientSecret: intent.clientSecret,
      orderId: intent.orderId,
    );

    final confirm = await gateway.confirmWalletPayment(
      orderId: intent.orderId,
      method: request.method,
      walletToken: token,
      deviceData: deviceData,
    );

    final statusStr = (confirm['status'] ?? '').toString().toLowerCase();
    final status = switch (statusStr) {
      'succeeded' || 'success' => PaymentStatus.succeeded,
      'pending' => PaymentStatus.pending,
      'canceled' => PaymentStatus.canceled,
      _ => PaymentStatus.failed,
    };

    final result = PaymentResult(
      status: status,
      method: request.method,
      orderId: intent.orderId,
      receiptOrToken: token,
      gatewayReference: confirm['gatewayReference']?.toString(),
      message: confirm['message']?.toString(),
      raw: confirm,
    );

    return WalletPaymentResponse(result: result, gatewayResponse: confirm);
  }
}

class PciComplianceGuards {
  static void assertNoRawCardData(Map<String, dynamic> payload) {
    final forbiddenKeys = <String>{
      'cardNumber',
      'pan',
      'cvc',
      'cvv',
      'expiry',
      'expMonth',
      'expYear',
      'track1',
      'track2',
      'magstripe',
      'pin',
    };
    bool containsForbidden(Map<String, dynamic> m) {
      for (final e in m.entries) {
        final k = e.key.toString();
        if (forbiddenKeys.contains(k)) return true;
        final v = e.value;
        if (v is Map<String, dynamic> && containsForbidden(v)) return true;
        if (v is List) {
          for (final item in v) {
            if (item is Map<String, dynamic> && containsForbidden(item)) return true;
          }
        }
      }
      return false;
    }

    if (containsForbidden(payload)) {
      throw PaymentException(
        'pci_violation',
        'Payload contains prohibited raw card data. Use tokenization via gateway SDK/server.',
      );
    }
  }
}

class PaymentApi {
  final PaymentModule module;
  PaymentApi(this.module);

  Future<WalletPaymentResponse> applePay({
    required String merchantName,
    required String label,
    required String currency,
    required int amountMinor,
    required String countryCode,
    required String description,
    Map<String, dynamic>? metadata,
    Map<String, dynamic>? deviceData,
  }) {
    final req = WalletPaymentRequest(
      method: PaymentMethodType.applePay,
      currency: currency,
      amountMinor: amountMinor,
      countryCode: countryCode,
      description: description,
      metadata: metadata,
    );
    return module.payWithWallet(request: req, merchantName: merchantName, label: label, deviceData: deviceData);
  }

  Future<WalletPaymentResponse> googlePay({
    required String merchantName,
    required String label,
    required String currency,
    required int amountMinor,
    required String countryCode,
    required String description,
    Map<String, dynamic>? metadata,
    Map<String, dynamic>? deviceData,
  }) {
    final req = WalletPaymentRequest(
      method: PaymentMethodType.googlePay,
      currency: currency,
      amountMinor: amountMinor,
      countryCode: countryCode,
      description: description,
      metadata: metadata,
    );
    return module.payWithWallet(request: req, merchantName: merchantName, label: label, deviceData: deviceData);
  }
}